import React from "react";
import { useNavigate, useLocation } from "react-router-dom";

const Sidebar = () => {

  const navigate = useNavigate();
  const location = useLocation();

  const user = JSON.parse(localStorage.getItem("user"));

  // =============================
  // LOGOUT
  // =============================

  const logout = () => {

    localStorage.removeItem("token");
    localStorage.removeItem("user");

    navigate("/login");

  };


  // =============================
  // FREELANCER MENU
  // =============================

  const freelancerMenu = [

    {
      name: "Dashboard",
      path: "/freelancer/dashboard",
      icon: "📊"
    },

    {
      name: "Find Projects",
      path: "/freelancer/projects",
      icon: "🔎"
    },

    {
      name: "My Proposals",
      path: "/freelancer/proposals",
      icon: "📄"
    },

    {
      name: "Profile",
      path: "/freelancer/profile",
      icon: "👤"
    },

  ];


  // =============================
  // CLIENT MENU
  // =============================

  const clientMenu = [

    {
      name: "Dashboard",
      path: "/client/dashboard",
      icon: "📊"
    },

    {
      name: "Post Project",
      path: "/client/post-project",
      icon: "➕"
    },

    {
      name: "My Projects",
      path: "/client/my-projects",
      icon: "📁"
    },

    {
      name: "Freelancers",
      path: "/client/freelancers",
      icon: "👨‍💻"
    },

    {
      name: "Settings",
      path: "/client/settings",
      icon: "⚙️"
    },

  ];


  // =============================
  // ADMIN MENU
  // =============================

  const adminMenu = [

    {
      name: "Dashboard",
      path: "/admin/dashboard",
      icon: "📊"
    },

    {
      name: "Users",
      path: "/admin/users",
      icon: "👥"
    },

    {
      name: "Projects",
      path: "/admin/projects",
      icon: "📁"
    },

    {
      name: "Reports",
      path: "/admin/reports",
      icon: "📈"
    },

    {
      name: "Settings",
      path: "/admin/settings",
      icon: "⚙️"
    },

  ];


  // =============================
  // SELECT MENU BASED ON ROLE
  // =============================

  let menu = [];

  if (user?.role === "freelancer") menu = freelancerMenu;

  if (user?.role === "client") menu = clientMenu;

  if (user?.role === "admin") menu = adminMenu;



  return (

    <div className="w-64 h-screen bg-gradient-to-b from-[#0f172a] to-[#020617] text-white fixed flex flex-col justify-between shadow-xl">


      {/* TOP */}

      <div>


        {/* LOGO */}

        <div className="p-6 border-b border-gray-700">

          <h1
            className="text-xl font-bold flex items-center gap-2 cursor-pointer"
            onClick={() => navigate("/")}
          >

            <span className="bg-green-500 p-2 rounded">

              💼

            </span>

            FreelanceHub

          </h1>

        </div>



        {/* USER INFO */}

        <div className="p-6 border-b border-gray-700">

          <div className="flex items-center gap-3">


            <div className="bg-green-500 w-10 h-10 rounded-full flex items-center justify-center font-bold">

              {user?.name?.charAt(0)}

            </div>


            <div>

              <p className="font-semibold">

                {user?.name}

              </p>


              <p className="text-sm text-gray-400 capitalize">

                {user?.role}

              </p>

            </div>

          </div>

        </div>



        {/* MENU TITLE */}

        <div className="px-6 pt-4 text-gray-400 text-sm">

          MENU

        </div>



        {/* MENU */}

        <ul className="p-4 space-y-2">


          {menu.map((item, index) => (

            <li

              key={index}

              onClick={() => navigate(item.path)}

              className={`

              flex items-center gap-3
              cursor-pointer
              p-3
              rounded-lg
              transition-all

              ${location.pathname === item.path

                  ?

                  "bg-green-500 text-white shadow-lg"

                  :

                  "hover:bg-gray-700"

                }

              `}

            >

              <span>

                {item.icon}

              </span>

              {item.name}

            </li>

          ))}


        </ul>


      </div>



      {/* LOGOUT */}

      <div className="p-6 border-t border-gray-700">


        <button

          onClick={logout}

          className="flex items-center gap-2 text-gray-300 hover:text-white"

        >

          🚪 Logout

        </button>


      </div>



    </div>

  );

};

export default Sidebar;
